def solve(nums: Array[Long], k: Long): Long = {
    var totalSum = 0L
    var modCount = 0L

    for (num <- nums) {
        totalSum += num
        modCount = (modCount + num % k) % k
    }

    if (modCount == 0L) {
        0L
    } else {
        totalSum - (k - modCount)
    }
}
