function solve(nums: number[], k: number): number {
    let totalSum = 0;
    let modCount = 0;

    for (const num of nums) {
        totalSum += num;
        modCount = (modCount + num % k) % k;
    }

    if (modCount === 0) {
        return 0;
    }

    return totalSum - (k - modCount);
}
